import CameraAltIcon from '@mui/icons-material/CameraAlt';
import {
  Box,
  Button,
  FormControl,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import { Dispatch, FC, SetStateAction, useEffect, useState } from 'react';

import CriticalError from '@/components/common/critical-error';
import { ImageOrAvatar } from '@/components/common/image-or-avatar';
import ValidationError from '@/components/common/validation-error';
import AppConstants from '@/constants/app.constants';
import useServicesHook from '@/hooks';
import { ServiceError } from '@/services/errors/service-error';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';

import { CommonModal } from '../common-modal';

export type EditTeamParam = {
  name: string;
  previewUrl: string | null;
  imageFile?: File;
};

export const EditTeamModal: FC<{
  teamId: string;
  defaultData: EditTeamParam;
  isOpen: boolean;
  setIsOpen: Dispatch<SetStateAction<boolean>>;
  onSuccess?: Function;
  onCancel?: Function;
}> = ({ teamId, defaultData, isOpen, setIsOpen, onSuccess, onCancel }) => {
  const { services } = useServicesHook();

  const [teamData, setTeamData] = useState<{
    name: string;
    imageFile?: File;
    previewUrl: string | null;
  }>({
    name: defaultData.name,
    previewUrl: defaultData.previewUrl,
  });

  const [error, setError] = useState<ServiceError | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  const onClickSaveBtn = async (teamId: string) => {
    wrapForLoading(setIsSubmitting, async () => {
      if (teamData.imageFile) {
        if (teamData.imageFile.size > AppConstants.THUMBNAIL_FILE_SIZE_LIMIT) {
          setError(
            new ServiceError(new Error(translate('thumbnail_file_too_large'))),
          );
          return;
        }
      }
      const { team, error } = await services.default.team.putTeam(
        teamId,
        teamData.name,
        teamData.imageFile!,
      );

      if (error) {
        setError(error);
        return;
      }
      onSuccess?.(team);
      setIsOpen(false);
    });
  };

  useEffect(() => {
    setError(null);
    setTeamData({
      name: defaultData.name,
      previewUrl: defaultData.previewUrl,
    });
  }, [isOpen]);

  return (
    <CommonModal isOpen={isOpen} setIsOpen={setIsOpen} onClose={onCancel}>
      <Typography variant="h4">{translate('edit_team')}</Typography>

      <Stack
        alignItems="stretch"
        direction="column"
        spacing={2}
        sx={{ py: 1 }}
        useFlexGap
      >
        <Button
          color="neutral"
          component="label"
          role={undefined}
          sx={{
            m: '0 auto',
            p: 0,
            position: 'relative',
          }}
          tabIndex={-1}
          variant="contained"
        >
          <ImageOrAvatar
            url={teamData?.previewUrl ?? AppConstants.NO_IMAGE_2ND_BASE_URL}
            width={120}
            height={120}
          />
          <Box
            sx={{
              position: 'absolute',
              top: '50%',
              left: '50%',
              transform: 'translate(-50%, -50%)',
              padding: '4px',
              backgroundColor: 'rgba(0, 0, 0, 0.5)',
              borderRadius: '50%',
              color: 'white',
              display: 'flex',
            }}
          >
            <CameraAltIcon fontSize="small" />
          </Box>
          <input
            accept=".jpg, .jpeg, .png, .webp"
            style={{ display: 'none' }}
            id="team-image-upload"
            type="file"
            onChange={(e) => {
              const file = e.target.files?.[0];
              if (file) {
                setTeamData({
                  ...teamData,
                  imageFile: file,
                  previewUrl: URL.createObjectURL(file),
                });
              }
            }}
          />
        </Button>
        <FormControl>
          <TextField
            label={translate('name')}
            value={teamData.name}
            onChange={(e) => {
              setTeamData({
                ...teamData,
                name: e.target.value,
              });
            }}
          />
          <ValidationError error={error} pos={['name']} />
        </FormControl>

        <CriticalError
          messagePrefix={translate('failed_to_edit_team') + ' '}
          error={error}
        />

        <Button
          color="primary"
          fullWidth
          loading={isSubmitting}
          variant="contained"
          onClick={() => {
            onClickSaveBtn(teamId);
          }}
        >
          {translate('button_save_changes')}
        </Button>

        <Button
          fullWidth
          color="neutral"
          onClick={() => {
            setIsOpen(false);
          }}
        >
          {translate('button_cancel')}
        </Button>
      </Stack>
    </CommonModal>
  );
};

