import _ from 'lodash';
import moment from 'moment';
import { NextRouter, useRouter } from 'next/router';
import { useCallback, useMemo } from 'react';

import AppConstants from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import { AiCoachReportsService } from '@/services/http/ai-coach-reports.service';
import { AuthService } from '@/services/http/auth.service';
import { BallsService } from '@/services/http/balls.service';
import { FilesService } from '@/services/http/files.service';
import MastersService from '@/services/http/masters.service';
import { PaymentService } from '@/services/http/payment.service';
import { PlayersService } from '@/services/http/players.service';
import { ResourcesService } from '@/services/http/resources.service';
import { SessionsService } from '@/services/http/sessions.service';
import { SuperAdminService } from '@/services/http/super-admin.service';
import { TeamsService } from '@/services/http/teams.service';
import { UsersService } from '@/services/http/users.service';
import { ImageService } from '@/services/image/image.service';
import { AiCoachReportsApiInterface } from '@/services/interfaces/ai-coach-reports-api.interface';
import { BallsApiInterface } from '@/services/interfaces/balls-api.interface';
import { MastersApiInterface } from '@/services/interfaces/masters-api.interface';
import { PaymentApiInterface } from '@/services/interfaces/payment-api.interface';
import { PlayersApiInterface } from '@/services/interfaces/players-api.interface';
import { ResourcesApiInterface } from '@/services/interfaces/resources-api.interface';
import { SessionsApiInterface } from '@/services/interfaces/sessions-api.interface';
import { SuperAdminApiInterface } from '@/services/interfaces/super-admin-api.interface';
import { TeamsApiInterface } from '@/services/interfaces/teams-api.interface';
import { UsersApiInterface } from '@/services/interfaces/users-api.interface';
import { LocalStorageService } from '@/services/local-storage/local-storage.service';
import { VideoService } from '@/services/video/video.service';
import { store, useDispatch, useSelector } from '@/store';
import { actions as masterDataActions } from '@/store/slices/master.slice';
import { logger } from '@/utils/logger';

const logDateFormat = AppConstants.API_DATETIME_FORMAT;

const checkMaintenanceFilePeriodically = async <T>(
  label: string,
  lastCheckedAt: Date | null,
  getter: () => Promise<{ data: T; needsReloading: boolean } | null>,
  setter: (checkedTimestamp: Date, data: T | null) => Promise<void>,
  action: () => Promise<void>,
) => {
  // logger.debug(`[${label}] Checking app info...`)
  const CHECK_TIMESPAN = AppConstants.DEPLOYMENT_CHECKING_TIMESPAN_MIN; // minutes
  if (!lastCheckedAt) {
    logger.debug(`[${label}] Empty checking date`);
    return;
  }
  const localMomentOfFrontend = moment(lastCheckedAt);
  const nowMoment = moment(new Date());
  if (
    localMomentOfFrontend.clone().add(CHECK_TIMESPAN, 'minute') >
    nowMoment.clone()
  ) {
    // The function is called but the span is too short, then return
    const s = localMomentOfFrontend
      .clone()
      .add(CHECK_TIMESPAN, 'minute')
      .utc()
      .format(logDateFormat);
    logger.debug(`[${label}] Next checking date: ${s}`);
    return;
  }

  const result = await getter();

  await setter(nowMoment.toDate(), result?.data ?? null);

  if (result?.needsReloading) {
    await action();
  }
};

type ServicesHook = {
  dispatch: typeof store.dispatch;
  router: NextRouter;
  services: {
    default: {
      aiCoachReports: AiCoachReportsApiInterface;
      auth: AuthService;
      player: PlayersApiInterface;
      resource: ResourcesApiInterface;
      session: SessionsApiInterface;
      ball: BallsApiInterface;
      superAdmin: SuperAdminApiInterface;
      team: TeamsApiInterface;
      user: UsersApiInterface;
      file: FilesService;
      master: MastersApiInterface;
      payment: PaymentApiInterface;
    };
    // 非通信系
    localStorage: LocalStorageService;
    image: ImageService;
    video: VideoService;
  };
  reloader: {
    reloadIfNeeded: () => Promise<void>;
  };
};

/**
 * 多くのページで利用するサービス的な処理（APIやlocalStorageなど外部データの参照や共通機能）を定義する。
 * @returns
 */
const useServicesHook = (): ServicesHook => {
  const apiServices = useMemo(() => {
    return {
      aiCoachReports: new AiCoachReportsService(),
      auth: new AuthService(),
      ball: new BallsService(),
      player: new PlayersService(),
      resource: new ResourcesService(),
      session: new SessionsService(),
      superAdmin: new SuperAdminService(),
      team: new TeamsService(),
      user: new UsersService(),
      file: new FilesService(),
      master: new MastersService(),
      payment: new PaymentService(),
    };
  }, []);
  const dispatch = useDispatch();
  const deploymentCheckedAt = useSelector(
    (state) => state.master.deploymentCheckedAt,
  );
  const maintenanceCheckedAt = useSelector(
    (state) => state.master.maintenanceCheckedAt,
  );

  const checkDeployment = useCallback(async () => {
    checkMaintenanceFilePeriodically(
      'reloading',
      deploymentCheckedAt,
      async () => {
        const localMomentOfFrontend = moment(deploymentCheckedAt);
        try {
          // Gets latest deployment timestamp
          const info = await apiServices.file.getLatestVersionTimestamp();
          const deploymentMoment = moment(info.timestamp);
          const d = deploymentMoment.clone().utc().format(logDateFormat);
          const l = localMomentOfFrontend.clone().utc().format(logDateFormat);
          // true if the new app is deployed (d) after the time last checked (l)
          const needsReloading =
            localMomentOfFrontend.clone() < deploymentMoment.clone();
          logger.debug(
            `[reloading] D: ${d}, L: ${l}, reload: ${needsReloading}`,
          );
          return {
            data: {},
            needsReloading,
          };
        } catch (e) {
          return null;
        }
      },
      async (currentTimestamp, data) => {
        dispatch(masterDataActions.setDeploymentCheckedDate(currentTimestamp));
      },
      async () => {
        logger.debug(`[reloading] executing action...`);
        setTimeout(() => {
          window.location.reload();
        }, 1000);
      },
    );
    checkMaintenanceFilePeriodically(
      'maintenance',
      maintenanceCheckedAt,
      async () => {
        const nowMoment = moment(new Date());
        try {
          // Gets latest deployment timestamp
          const result = await apiServices.file.getMaintenanceInfo();
          const isInMaintenance = result.info?.isInMaintenance ?? false;
          logger.debug(`[maintenance] status: ${isInMaintenance}`);
          return {
            data: result.info,
            needsReloading: isInMaintenance,
          };
        } catch (e) {
          return null;
        }
      },
      async (currentTimestamp, data) => {
        dispatch(masterDataActions.setMaintenanceCheckedDate(currentTimestamp));
      },
      async () => {
        logger.debug(`[maintenance] executing action...`);
        setTimeout(() => {
          location.href = PAGE_INFO.MAINTENANCE.href();
        }, 1000);
      },
    );
  }, [deploymentCheckedAt, apiServices.file]);

  return {
    dispatch,
    router: useRouter(),
    services: useMemo(() => {
      return {
        default: apiServices,
        // 非通信系
        localStorage: new LocalStorageService(),
        image: new ImageService(),
        video: new VideoService(),
      };
    }, []),
    reloader: {
      reloadIfNeeded: checkDeployment,
    },
  };
};

export default useServicesHook;

