import { useState, useCallback, useRef } from 'react';

/**
 * フォーム送信時の連打防止機能を提供するカスタムフック
 *
 * useRef を使用して同期的なロックを実装し、React の state 更新の非同期性による
 * 競合状態を回避します。これにより、同一イベントループ内での連続クリックも
 * 確実に防止できます。
 *
 * @example
 * ```tsx
 * const { isSubmitting, executeWithGuard } = useSubmitGuard();
 *
 * const handleSubmit = async () => {
 *   await executeWithGuard(async () => {
 *     // 送信処理
 *     await apiCall();
 *   });
 * };
 *
 * return (
 *   <Button
 *     loading={isSubmitting}
 *     disabled={isSubmitting}
 *     onClick={handleSubmit}
 *   >
 *     送信
 *   </Button>
 * );
 * ```
 */
export const useSubmitGuard = () => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const submittingRef = useRef(false);

  const executeWithGuard = useCallback(async <T>(
    fn: () => Promise<T>,
  ): Promise<T | null> => {
    // 同期的なチェック（競合状態を防ぐ）
    if (submittingRef.current) {
      return null;
    }

    // 即座にロックを取得
    submittingRef.current = true;
    setIsSubmitting(true);

    try {
      return await fn();
    } finally {
      // ロックを解放
      submittingRef.current = false;
      setIsSubmitting(false);
    }
  }, []);

  return { isSubmitting, executeWithGuard };
};

