import _ from 'lodash';

export const wrapForLoading = async <T>(
  stateSetter: (state: boolean) => void,
  funct: (...args: any) => T,
) => {
  stateSetter(true);
  try {
    return await funct();
  } finally {
    stateSetter(false);
  }
};

const replaceSingleEmptyString = (
  data: string,
  replaceWithUndefined = false,
) => {
  const strVal = (data as string).trim();
  return strVal.length == 0
    ? replaceWithUndefined
      ? undefined
      : null
    : strVal;
};

export const replaceEmptyString = (
  data: any,
  replaceWithUndefined = false,
  recursive = false,
): any => {
  if (_.isString(data)) {
    return replaceSingleEmptyString(data, replaceWithUndefined);
  }
  if (!_.isObject(data)) {
    return data;
  }
  if (_.isArray(data) && recursive) {
    return _.map(data, (x) =>
      replaceEmptyString(x, replaceWithUndefined, true),
    );
  }
  return _.transform(
    data,
    (memo: any, val, key) => {
      if (recursive) {
        memo[key] = replaceEmptyString(val, replaceWithUndefined, true);
      } else {
        memo[key] = _.isString(val)
          ? replaceSingleEmptyString(val, replaceWithUndefined)
          : val;
      }
    },
    {},
  );
};

export const isNilOrEmpty = (s: string | undefined | null): boolean => {
  return _.isNil(s) || _.isEmpty(s);
};

export const snakizeKeys = (data: any, recursive = false): any => {
  if (!_.isObject(data)) {
    return data;
  }
  if (_.isArray(data) && recursive) {
    return _.map(data, (x) => snakizeKeys(x, true));
  }
  return _.transform(
    data,
    (memo: any, val, key) => {
      memo[_.snakeCase(key)] = recursive ? snakizeKeys(val, true) : val;
    },
    {},
  );
};

export const camelizeKeys = (data: any, recursive = false): any => {
  if (!_.isObject(data)) {
    return data;
  }
  if (_.isArray(data) && recursive) {
    return _.map(data, (x) => camelizeKeys(x, true));
  }
  return _.transform(
    data,
    (memo: any, val, key) => {
      memo[_.camelCase(key)] = recursive ? camelizeKeys(val, true) : val;
    },
    {},
  );
};

